public class RemoveElements {
    public static SinglyLinkedList.Node remove(SinglyLinkedList.Node head, int val) {
        // Input: head node and target integer value

        // Storage: Sentinel node to simplify head removals
        SinglyLinkedList.Node dummy = new SinglyLinkedList.Node(0);
        dummy.next = head;
        SinglyLinkedList.Node current = dummy;

        // Process: Traversal and link updates
        while (current.next != null) {
            if (current.next.val == val) {
                current.next = current.next.next; // Bypass matched node
            } else {
                current = current.next; // Shift pointer
            }
        }

        // Output: Return new head node reference
        return dummy.next;
    }
}

