public class ReverseList {
    public static SinglyLinkedList.Node reverse(SinglyLinkedList.Node head) {
        // Input: Head pointer of list

        // Storage: Pointer variables
        SinglyLinkedList.Node prev = null;
        SinglyLinkedList.Node current = head;

        // Process: Pointer inversion loop
        while (current != null) {
            SinglyLinkedList.Node nextTemp = current.next; // Save next node
            current.next = prev;        // Invert pointer
            prev = current;             // Shift prev forward
            current = nextTemp;         // Shift current forward
        }

        // Output: Return new head of reversed list
        return prev;
    }
}

public class PalindromeList {
    public static boolean isPalindrome(SinglyLinkedList.Node head) {
        // Input: Head node
        if (head == null || head.next == null) return true;

        // Storage & Process: Find middle
        SinglyLinkedList.Node slow = head;
        SinglyLinkedList.Node fast = head;
        while (fast.next != null && fast.next.next != null) {
            slow = slow.next;
            fast = fast.next.next;
        }

        // Process: Reverse second half
        SinglyLinkedList.Node secondHead = ReverseList.reverse(slow.next);
        SinglyLinkedList.Node p1 = head;       // Storage
        SinglyLinkedList.Node p2 = secondHead; // Storage

        // Process: Compare values
        boolean palindrome = true; // Storage
        while (p2 != null) {
            if (p1.val != p2.val) {
                palindrome = false;
                break;
            }
            p1 = p1.next;
            p2 = p2.next;
        }

        // Output: Return outcome
        return palindrome;
    }
}

