public class MiddleNode {
    public static SinglyLinkedList.Node getMiddle(SinglyLinkedList.Node head) {
        // Input: Head pointer of list

        // Storage: Slow and fast pointers
        SinglyLinkedList.Node slow = head;
        SinglyLinkedList.Node fast = head;

        // Process: Two-pointer traversal
        while (fast != null && fast.next != null) {
            slow = slow.next;
            fast = fast.next.next;
        }

        // Output: Return middle node pointer
        return slow;
    }
}

