public class BinaryToDecimal {
    public static int convert(SinglyLinkedList.Node head) {
        // Input: Head pointer representing MSB (most significant bit)

        // Storage: Decimal accumulator
        int decimalValue = 0;
        SinglyLinkedList.Node current = head; // Storage

        // Process: Binary shift accumulation
        while (current != null) {
            decimalValue = (decimalValue * 2) + current.val;
            current = current.next;
        }

        // Output: Return decimal result
        return decimalValue;
    }
}
